# solution.py
"""Team Collaboration Manager.

A thread-safe, in-memory backend for a small team-collaboration product.  It
provides user / project / task management, threaded messaging with
attachments, a performance dashboard (completion rate, average completion
time, peer ratings) and exportable reports (CSV and PDF).

Design notes
------------
* **Single shared lock.**  Every public mutation and read is guarded by one
  re-entrant lock that is shared by the manager and all of its sub-managers.
  This keeps compound operations (allocate id -> store entity -> update
  indexes) atomic and makes the whole API safe under concurrent use.
* **Globally unique ids.**  A single monotonic counter hands out ids starting
  at ``1`` for every entity type, so a user, a project, a task and a message
  never collide.
* **Getter isolation.**  Everything returned to a caller is a deep copy, so
  mutating a returned object (or list) can never corrupt internal state.
* **Layered design.**  ``TeamCollaborationManager`` is a thin facade that
  delegates to focused sub-managers (users, projects, tasks, messages,
  performance, reports), all sharing one :class:`_Store`.

The module only uses the Python standard library.
"""

import copy
import csv
import io
import threading
from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum
from typing import Callable, Dict, List, Optional, Tuple

__all__ = [
    "TeamCollaborationManager",
    "UserRole",
    "TaskStatus",
    "ReportFormat",
    "ReportType",
    "TeamCollaborationError",
    "ValidationError",
    "NotFoundError",
    "AuthorizationError",
    "DuplicateError",
    "ConflictError",
    "User",
    "Project",
    "Task",
    "Message",
    "Attachment",
    "Rating",
]


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class UserRole(Enum):
    """Authorization role attached to a user."""

    ADMIN = "admin"
    MANAGER = "manager"
    MEMBER = "member"
    VIEWER = "viewer"


class TaskStatus(Enum):
    """Lifecycle status of a task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class ReportFormat(Enum):
    """Supported export formats for reports."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    """Identifies the shape of a generated report dictionary."""

    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for every error raised by this module."""


class ValidationError(TeamCollaborationError):
    """Raised when input fails a validation rule."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not allowed to perform an operation."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint would be violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with the current state."""


# ---------------------------------------------------------------------------
# Data models
# ---------------------------------------------------------------------------
@dataclass
class User:
    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    id: int
    name: str
    description: str
    start_date: datetime
    end_date: datetime
    owner_id: int
    created_at: datetime


@dataclass
class Attachment:
    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class Task:
    id: int
    project_id: int
    title: str
    assignee_id: Optional[int]
    status: TaskStatus
    deadline: Optional[datetime]
    created_at: datetime
    started_at: Optional[datetime] = None
    completed_at: Optional[datetime] = None


@dataclass
class Message:
    id: int
    author_id: int
    body: str
    project_id: Optional[int]
    task_id: Optional[int]
    parent_id: Optional[int]
    created_at: datetime
    attachments: List[Attachment] = field(default_factory=list)
    edited_at: Optional[datetime] = None


@dataclass
class Rating:
    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str
    task_id: Optional[int]
    created_at: datetime


# ---------------------------------------------------------------------------
# Small validation helpers
# ---------------------------------------------------------------------------
def _require_text(value: object, field_name: str) -> str:
    """Return a stripped, non-empty string or raise ``ValidationError``."""

    if not isinstance(value, str) or not value.strip():
        raise ValidationError("{0} must be a non-empty string".format(field_name))
    return value.strip()


def _valid_email(email: object) -> bool:
    if not isinstance(email, str):
        return False
    email = email.strip()
    if not email or "@" not in email:
        return False
    local, _, domain = email.partition("@")
    return bool(local) and bool(domain)


def _copy(obj):
    """Deep copy used to isolate returned values from internal state."""

    return copy.deepcopy(obj)


# ---------------------------------------------------------------------------
# Shared store
# ---------------------------------------------------------------------------
class _Store:
    """Holds every entity, the shared lock and all secondary indexes.

    All methods assume the caller already holds :attr:`lock`.  The store is
    deliberately "dumb": it performs lookups, id allocation and index
    bookkeeping, while business rules live in the sub-managers.
    """

    def __init__(self, now: Callable[[], datetime], lock: threading.RLock) -> None:
        self.now = now
        self.lock = lock
        self._next_id = 0

        # Primary entity tables.
        self.users: Dict[int, User] = {}
        self.projects: Dict[int, Project] = {}
        self.tasks: Dict[int, Task] = {}
        self.messages: Dict[int, Message] = {}
        self.ratings: Dict[int, Rating] = {}

        # Uniqueness indexes (case-insensitive keys -> user id).
        self.username_index: Dict[str, int] = {}
        self.email_index: Dict[str, int] = {}

        # Secondary relationship indexes.
        self.tasks_by_project: Dict[int, set] = {}
        self.tasks_by_assignee: Dict[int, set] = {}
        self.messages_by_project: Dict[int, set] = {}
        self.messages_by_task: Dict[int, set] = {}
        self.ratings_by_ratee: Dict[int, set] = {}

    # -- id allocation -----------------------------------------------------
    def next_id(self) -> int:
        self._next_id += 1
        return self._next_id

    # -- lookups -----------------------------------------------------------
    def require_user(self, user_id: int) -> User:
        user = self.users.get(user_id)
        if user is None:
            raise NotFoundError("user {0} not found".format(user_id))
        return user

    def require_project(self, project_id: int) -> Project:
        project = self.projects.get(project_id)
        if project is None:
            raise NotFoundError("project {0} not found".format(project_id))
        return project

    def require_task(self, task_id: int) -> Task:
        task = self.tasks.get(task_id)
        if task is None:
            raise NotFoundError("task {0} not found".format(task_id))
        return task

    def require_message(self, message_id: int) -> Message:
        message = self.messages.get(message_id)
        if message is None:
            raise NotFoundError("message {0} not found".format(message_id))
        return message

    # -- index helpers -----------------------------------------------------
    @staticmethod
    def _add(index: Dict[int, set], key: int, value: int) -> None:
        index.setdefault(key, set()).add(value)

    @staticmethod
    def _discard(index: Dict[int, set], key: int, value: int) -> None:
        bucket = index.get(key)
        if bucket is not None:
            bucket.discard(value)
            if not bucket:
                index.pop(key, None)

    def set_task_assignee(self, task: Task, assignee_id: Optional[int]) -> None:
        """Update a task's assignee and keep the assignee index in sync."""

        if task.assignee_id is not None:
            self._discard(self.tasks_by_assignee, task.assignee_id, task.id)
        task.assignee_id = assignee_id
        if assignee_id is not None:
            self._add(self.tasks_by_assignee, assignee_id, task.id)

    # -- cascading removal -------------------------------------------------
    def remove_message(self, message_id: int) -> None:
        message = self.messages.pop(message_id, None)
        if message is None:
            return
        if message.project_id is not None:
            self._discard(self.messages_by_project, message.project_id, message_id)
        if message.task_id is not None:
            self._discard(self.messages_by_task, message.task_id, message_id)

    def remove_task(self, task_id: int) -> None:
        task = self.tasks.pop(task_id, None)
        if task is None:
            return
        self._discard(self.tasks_by_project, task.project_id, task_id)
        if task.assignee_id is not None:
            self._discard(self.tasks_by_assignee, task.assignee_id, task_id)
        for message_id in list(self.messages_by_task.get(task_id, ())):
            self.remove_message(message_id)
        self.messages_by_task.pop(task_id, None)

    def remove_project(self, project_id: int) -> None:
        for task_id in list(self.tasks_by_project.get(project_id, ())):
            self.remove_task(task_id)
        self.tasks_by_project.pop(project_id, None)
        for message_id in list(self.messages_by_project.get(project_id, ())):
            self.remove_message(message_id)
        self.messages_by_project.pop(project_id, None)
        self.projects.pop(project_id, None)

    # -- metric helpers ----------------------------------------------------
    def tasks_of_user(self, user_id: int) -> List[Task]:
        return [self.tasks[t] for t in self.tasks_by_assignee.get(user_id, ())]

    def tasks_of_project(self, project_id: int) -> List[Task]:
        return [self.tasks[t] for t in self.tasks_by_project.get(project_id, ())]

    @staticmethod
    def completion_rate(tasks: List[Task]) -> float:
        if not tasks:
            return 0.0
        completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
        return completed / len(tasks)

    @staticmethod
    def average_completion_time(tasks: List[Task]) -> Optional[float]:
        durations = [
            (t.completed_at - t.started_at).total_seconds()
            for t in tasks
            if t.status == TaskStatus.COMPLETED
            and t.started_at is not None
            and t.completed_at is not None
        ]
        if not durations:
            return None
        return sum(durations) / len(durations)

    def rating_stats(self, user_id: int) -> Tuple[int, float, List[Rating]]:
        ratings = [self.ratings[r] for r in self.ratings_by_ratee.get(user_id, ())]
        ratings.sort(key=lambda r: r.id)
        if not ratings:
            return 0, 0.0, []
        average = sum(r.score for r in ratings) / len(ratings)
        return len(ratings), average, ratings


# ---------------------------------------------------------------------------
# Base sub-manager
# ---------------------------------------------------------------------------
class _SubManager:
    """Common base giving every sub-manager the shared store and lock."""

    def __init__(self, store: _Store) -> None:
        self._store = store
        self._lock = store.lock

    @property
    def _now(self) -> datetime:
        return self._store.now()


# ---------------------------------------------------------------------------
# User management
# ---------------------------------------------------------------------------
class UserManager(_SubManager):
    def register_user(
        self, username: str, email: str, role: UserRole = UserRole.MEMBER
    ) -> User:
        username = _require_text(username, "username")
        if not _valid_email(email):
            raise ValidationError("invalid email address")
        if not isinstance(role, UserRole):
            raise ValidationError("role must be a UserRole")
        email = email.strip()

        with self._lock:
            store = self._store
            if username.casefold() in store.username_index:
                raise DuplicateError("username already in use")
            if email.casefold() in store.email_index:
                raise DuplicateError("email already in use")

            user = User(
                id=store.next_id(),
                username=username,
                email=email,
                role=role,
                created_at=self._now,
            )
            store.users[user.id] = user
            store.username_index[username.casefold()] = user.id
            store.email_index[email.casefold()] = user.id
            return _copy(user)

    def get_user(self, user_id: int) -> User:
        with self._lock:
            return _copy(self._store.require_user(user_id))

    def list_users(self) -> List[User]:
        with self._lock:
            users = sorted(self._store.users.values(), key=lambda u: u.id)
            return [_copy(u) for u in users]

    def update_user(
        self,
        user_id: int,
        username: Optional[str] = None,
        email: Optional[str] = None,
        role: Optional[UserRole] = None,
    ) -> User:
        with self._lock:
            store = self._store
            user = store.require_user(user_id)

            new_username = user.username
            if username is not None:
                new_username = _require_text(username, "username")
                existing = store.username_index.get(new_username.casefold())
                if existing is not None and existing != user_id:
                    raise DuplicateError("username already in use")

            new_email = user.email
            if email is not None:
                if not _valid_email(email):
                    raise ValidationError("invalid email address")
                new_email = email.strip()
                existing = store.email_index.get(new_email.casefold())
                if existing is not None and existing != user_id:
                    raise DuplicateError("email already in use")

            if role is not None and not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            # Apply changes, keeping the uniqueness indexes consistent.
            if username is not None and new_username.casefold() != user.username.casefold():
                store.username_index.pop(user.username.casefold(), None)
            if username is not None:
                store.username_index[new_username.casefold()] = user_id
                user.username = new_username

            if email is not None and new_email.casefold() != user.email.casefold():
                store.email_index.pop(user.email.casefold(), None)
            if email is not None:
                store.email_index[new_email.casefold()] = user_id
                user.email = new_email

            if role is not None:
                user.role = role

            return _copy(user)

    def delete_user(self, user_id: int) -> None:
        with self._lock:
            store = self._store
            user = store.require_user(user_id)

            if any(p.owner_id == user_id for p in store.projects.values()):
                raise ConflictError("user owns one or more projects")

            for task in store.tasks_of_user(user_id):
                if task.status != TaskStatus.COMPLETED:
                    raise ConflictError("user has open assigned tasks")

            store.users.pop(user_id, None)
            store.username_index.pop(user.username.casefold(), None)
            store.email_index.pop(user.email.casefold(), None)
            store.tasks_by_assignee.pop(user_id, None)


# ---------------------------------------------------------------------------
# Project management
# ---------------------------------------------------------------------------
class ProjectManager(_SubManager):
    def create_project(
        self,
        name: str,
        start_date: datetime,
        end_date: datetime,
        owner_id: int,
        description: str = "",
    ) -> Project:
        name = _require_text(name, "name")
        if not isinstance(start_date, datetime) or not isinstance(end_date, datetime):
            raise ValidationError("start_date and end_date must be datetimes")
        if end_date < start_date:
            raise ValidationError("end_date cannot be before start_date")

        with self._lock:
            store = self._store
            store.require_user(owner_id)
            project = Project(
                id=store.next_id(),
                name=name,
                description=description or "",
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                created_at=self._now,
            )
            store.projects[project.id] = project
            return _copy(project)

    def get_project(self, project_id: int) -> Project:
        with self._lock:
            return _copy(self._store.require_project(project_id))

    def list_projects(self) -> List[Project]:
        with self._lock:
            projects = sorted(self._store.projects.values(), key=lambda p: p.id)
            return [_copy(p) for p in projects]

    def update_project(
        self,
        project_id: int,
        name: Optional[str] = None,
        start_date: Optional[datetime] = None,
        end_date: Optional[datetime] = None,
        description: Optional[str] = None,
    ) -> Project:
        with self._lock:
            project = self._store.require_project(project_id)

            new_name = project.name
            if name is not None:
                new_name = _require_text(name, "name")

            new_start = project.start_date
            if start_date is not None:
                if not isinstance(start_date, datetime):
                    raise ValidationError("start_date must be a datetime")
                new_start = start_date

            new_end = project.end_date
            if end_date is not None:
                if not isinstance(end_date, datetime):
                    raise ValidationError("end_date must be a datetime")
                new_end = end_date

            if new_end < new_start:
                raise ValidationError("end_date cannot be before start_date")

            project.name = new_name
            project.start_date = new_start
            project.end_date = new_end
            if description is not None:
                project.description = description
            return _copy(project)

    def delete_project(self, project_id: int) -> None:
        with self._lock:
            self._store.require_project(project_id)
            self._store.remove_project(project_id)


# ---------------------------------------------------------------------------
# Task management
# ---------------------------------------------------------------------------
class TaskManager(_SubManager):
    def create_task(
        self,
        project_id: int,
        title: str,
        assignee_id: Optional[int] = None,
        deadline: Optional[datetime] = None,
    ) -> Task:
        with self._lock:
            store = self._store
            project = store.require_project(project_id)
            title = _require_text(title, "title")
            if assignee_id is not None:
                store.require_user(assignee_id)
            if deadline is not None:
                if not isinstance(deadline, datetime):
                    raise ValidationError("deadline must be a datetime")
                if deadline < project.start_date:
                    raise ValidationError("deadline cannot be before project start")

            task = Task(
                id=store.next_id(),
                project_id=project_id,
                title=title,
                assignee_id=None,
                status=TaskStatus.NOT_STARTED,
                deadline=deadline,
                created_at=self._now,
            )
            store.tasks[task.id] = task
            store._add(store.tasks_by_project, project_id, task.id)
            if assignee_id is not None:
                store.set_task_assignee(task, assignee_id)
            return _copy(task)

    def get_task(self, task_id: int) -> Task:
        with self._lock:
            return _copy(self._store.require_task(task_id))

    def list_tasks_by_project(self, project_id: int) -> List[Task]:
        with self._lock:
            store = self._store
            store.require_project(project_id)
            ids = sorted(store.tasks_by_project.get(project_id, ()))
            return [_copy(store.tasks[i]) for i in ids]

    def list_tasks_by_assignee(self, user_id: int) -> List[Task]:
        with self._lock:
            store = self._store
            store.require_user(user_id)
            ids = sorted(store.tasks_by_assignee.get(user_id, ()))
            return [_copy(store.tasks[i]) for i in ids]

    def assign_task(self, task_id: int, user_id: int) -> Task:
        with self._lock:
            store = self._store
            task = store.require_task(task_id)
            store.require_user(user_id)
            store.set_task_assignee(task, user_id)
            return _copy(task)

    # Reassigning is semantically identical to assigning to a new user.
    reassign_task = assign_task

    def unassign_task(self, task_id: int) -> Task:
        with self._lock:
            store = self._store
            task = store.require_task(task_id)
            store.set_task_assignee(task, None)
            return _copy(task)

    def set_deadline(self, task_id: int, deadline: Optional[datetime]) -> Task:
        with self._lock:
            store = self._store
            task = store.require_task(task_id)
            if deadline is not None:
                if not isinstance(deadline, datetime):
                    raise ValidationError("deadline must be a datetime")
                project = store.require_project(task.project_id)
                if deadline < project.start_date:
                    raise ValidationError("deadline cannot be before project start")
            task.deadline = deadline
            return _copy(task)

    def update_status(self, task_id: int, status: TaskStatus) -> Task:
        if not isinstance(status, TaskStatus):
            raise ValidationError("status must be a TaskStatus")
        with self._lock:
            store = self._store
            task = store.require_task(task_id)
            now = self._now

            if status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None
            elif status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now

            task.status = status
            return _copy(task)


# ---------------------------------------------------------------------------
# Messaging
# ---------------------------------------------------------------------------
class MessageManager(_SubManager):
    def post_message(
        self,
        author_id: int,
        body: str,
        project_id: Optional[int] = None,
        task_id: Optional[int] = None,
        attachments: Optional[List[Tuple[str, bytes]]] = None,
        parent_id: Optional[int] = None,
    ) -> Message:
        with self._lock:
            store = self._store
            store.require_user(author_id)

            if (project_id is None) == (task_id is None):
                raise ValidationError(
                    "exactly one of project_id or task_id must be provided"
                )
            if project_id is not None:
                store.require_project(project_id)
            if task_id is not None:
                store.require_task(task_id)

            body = body if isinstance(body, str) else ""
            has_body = bool(body.strip())
            built_attachments = self._build_attachments(attachments, author_id)
            if not has_body and not built_attachments:
                raise ValidationError("message needs a body or an attachment")

            if parent_id is not None:
                store.require_message(parent_id)

            message = Message(
                id=store.next_id(),
                author_id=author_id,
                body=body,
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                created_at=self._now,
                attachments=built_attachments,
            )
            store.messages[message.id] = message
            if project_id is not None:
                store._add(store.messages_by_project, project_id, message.id)
            if task_id is not None:
                store._add(store.messages_by_task, task_id, message.id)
            return _copy(message)

    def _build_attachments(
        self, attachments: Optional[List[Tuple[str, bytes]]], uploader_id: int
    ) -> List[Attachment]:
        result: List[Attachment] = []
        for filename, data in attachments or []:
            result.append(self._make_attachment(filename, data, uploader_id))
        return result

    def _make_attachment(self, filename: str, data: bytes, uploader_id: int) -> Attachment:
        filename = _require_text(filename, "filename")
        payload = data if data is not None else b""
        try:
            size = len(payload)
        except TypeError:
            raise ValidationError("attachment data must be sized")
        return Attachment(
            filename=filename,
            size=size,
            uploaded_by=uploader_id,
            uploaded_at=self._now,
        )

    def edit_message(self, message_id: int, editor_id: int, new_body: str) -> Message:
        with self._lock:
            message = self._store.require_message(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may edit a message")
            body = new_body if isinstance(new_body, str) else ""
            if not body.strip() and not message.attachments:
                raise ValidationError("message needs a body or an attachment")
            message.body = body
            message.edited_at = self._now
            return _copy(message)

    def add_attachment(
        self, message_id: int, uploader_id: int, filename: str, data: bytes
    ) -> Message:
        with self._lock:
            message = self._store.require_message(message_id)
            if message.author_id != uploader_id:
                raise AuthorizationError("only the author may add attachments")
            attachment = self._make_attachment(filename, data, uploader_id)
            message.attachments.append(attachment)
            return _copy(message)

    def list_messages_by_project(self, project_id: int) -> List[Message]:
        with self._lock:
            store = self._store
            store.require_project(project_id)
            ids = sorted(store.messages_by_project.get(project_id, ()))
            return [_copy(store.messages[i]) for i in ids]

    def list_messages_by_task(self, task_id: int) -> List[Message]:
        with self._lock:
            store = self._store
            store.require_task(task_id)
            ids = sorted(store.messages_by_task.get(task_id, ()))
            return [_copy(store.messages[i]) for i in ids]

    def delete_message(self, message_id: int, requester_id: int) -> None:
        with self._lock:
            message = self._store.require_message(message_id)
            if message.author_id != requester_id:
                raise AuthorizationError("only the author may delete a message")
            self._store.remove_message(message_id)


# ---------------------------------------------------------------------------
# Performance dashboard
# ---------------------------------------------------------------------------
class PerformanceManager(_SubManager):
    def get_completion_rate(self, user_id: int) -> float:
        with self._lock:
            store = self._store
            store.require_user(user_id)
            return store.completion_rate(store.tasks_of_user(user_id))

    def get_average_completion_time(self, user_id: int) -> Optional[float]:
        with self._lock:
            store = self._store
            store.require_user(user_id)
            return store.average_completion_time(store.tasks_of_user(user_id))

    def submit_rating(
        self,
        rater_id: int,
        ratee_id: int,
        score: int,
        feedback: str = "",
        task_id: Optional[int] = None,
    ) -> Rating:
        with self._lock:
            store = self._store
            store.require_user(rater_id)
            store.require_user(ratee_id)
            if rater_id == ratee_id:
                raise ConflictError("users cannot rate themselves")
            if not isinstance(score, int) or isinstance(score, bool):
                raise ValidationError("score must be an integer")
            if score < 1 or score > 5:
                raise ValidationError("score must be between 1 and 5")
            if task_id is not None:
                store.require_task(task_id)

            rating = Rating(
                id=store.next_id(),
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback or "",
                task_id=task_id,
                created_at=self._now,
            )
            store.ratings[rating.id] = rating
            store._add(store.ratings_by_ratee, ratee_id, rating.id)
            return _copy(rating)

    def get_ratings_summary(self, user_id: int) -> Dict[str, object]:
        with self._lock:
            store = self._store
            store.require_user(user_id)
            count, average, ratings = store.rating_stats(user_id)
            return {
                "count": count,
                "average": average,
                "ratings": [_copy(r) for r in ratings],
            }

    def get_user_dashboard(self, user_id: int) -> Dict[str, object]:
        with self._lock:
            store = self._store
            store.require_user(user_id)
            tasks = store.tasks_of_user(user_id)
            count, average, _ = store.rating_stats(user_id)
            status_counts = self._status_counts(tasks)
            return {
                "user_id": user_id,
                "total_tasks": len(tasks),
                "completed_tasks": status_counts[TaskStatus.COMPLETED],
                "in_progress_tasks": status_counts[TaskStatus.IN_PROGRESS],
                "not_started_tasks": status_counts[TaskStatus.NOT_STARTED],
                "completion_rate": store.completion_rate(tasks),
                "average_completion_time": store.average_completion_time(tasks),
                "rating_count": count,
                "rating_average": average,
            }

    @staticmethod
    def _status_counts(tasks: List[Task]) -> Dict[TaskStatus, int]:
        counts = {status: 0 for status in TaskStatus}
        for task in tasks:
            counts[task.status] += 1
        return counts


# ---------------------------------------------------------------------------
# Reports
# ---------------------------------------------------------------------------
class ReportManager(_SubManager):
    def project_progress_report(self, project_id: int) -> Dict[str, object]:
        with self._lock:
            store = self._store
            store.require_project(project_id)
            tasks = store.tasks_of_project(project_id)
            now = self._now

            status_counts = {status.value: 0 for status in TaskStatus}
            overdue = 0
            per_assignee: Dict[int, Dict[str, object]] = {}
            for task in tasks:
                status_counts[task.status.value] += 1
                if (
                    task.deadline is not None
                    and task.deadline < now
                    and task.status != TaskStatus.COMPLETED
                ):
                    overdue += 1
                if task.assignee_id is not None:
                    per_assignee.setdefault(task.assignee_id, []).append(task)

            per_assignee_summary = {
                uid: {
                    "total_tasks": len(items),
                    "completed_tasks": sum(
                        1 for t in items if t.status == TaskStatus.COMPLETED
                    ),
                    "completion_rate": store.completion_rate(items),
                }
                for uid, items in per_assignee.items()
            }

            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": len(tasks),
                "status_counts": status_counts,
                "completion_rate": store.completion_rate(tasks),
                "overdue_tasks": overdue,
                "per_assignee": per_assignee_summary,
            }

    def team_performance_report(
        self, project_id: Optional[int] = None
    ) -> Dict[str, object]:
        with self._lock:
            store = self._store
            if project_id is not None:
                store.require_project(project_id)
                tasks = store.tasks_of_project(project_id)
            else:
                tasks = list(store.tasks.values())

            grouped: Dict[int, List[Task]] = {}
            for task in tasks:
                if task.assignee_id is not None:
                    grouped.setdefault(task.assignee_id, []).append(task)

            rows = []
            for user_id in sorted(grouped):
                user_tasks = grouped[user_id]
                user = store.users.get(user_id)
                count, average, _ = store.rating_stats(user_id)
                rows.append(
                    {
                        "user_id": user_id,
                        "username": user.username if user else None,
                        "total_tasks": len(user_tasks),
                        "completed_tasks": sum(
                            1 for t in user_tasks if t.status == TaskStatus.COMPLETED
                        ),
                        "completion_rate": store.completion_rate(user_tasks),
                        "average_completion_time": store.average_completion_time(
                            user_tasks
                        ),
                        "rating_count": count,
                        "rating_average": average,
                    }
                )

            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "rows": rows,
            }

    def individual_performance_report(self, user_id: int) -> Dict[str, object]:
        with self._lock:
            store = self._store
            user = store.require_user(user_id)
            tasks = sorted(store.tasks_of_user(user_id), key=lambda t: t.id)
            count, average, _ = store.rating_stats(user_id)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)

            task_rows = [
                {
                    "task_id": t.id,
                    "title": t.title,
                    "status": t.status.value,
                    "deadline": t.deadline.isoformat() if t.deadline else "",
                }
                for t in tasks
            ]

            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "username": user.username,
                "total_tasks": len(tasks),
                "completed_tasks": completed,
                "completion_rate": store.completion_rate(tasks),
                "average_completion_time": store.average_completion_time(tasks),
                "rating_count": count,
                "rating_average": average,
                "tasks": task_rows,
            }

    # -- export ------------------------------------------------------------
    def export_report(self, report: Dict[str, object], fmt: ReportFormat):
        if not isinstance(fmt, ReportFormat):
            raise ValidationError("fmt must be a ReportFormat")
        if not isinstance(report, dict):
            raise ValidationError("report must be a report dictionary")
        if fmt == ReportFormat.CSV:
            return self._to_csv(report)
        return self._to_pdf(report)

    def _to_csv(self, report: Dict[str, object]) -> str:
        report_type = report.get("report_type")
        buffer = io.StringIO()
        writer = csv.writer(buffer)

        if report_type == ReportType.TEAM_PERFORMANCE.value:
            header = [
                "user_id",
                "username",
                "total_tasks",
                "completed_tasks",
                "completion_rate",
                "average_completion_time",
                "rating_count",
                "rating_average",
            ]
            writer.writerow(header)
            for row in report.get("rows", []):
                writer.writerow([row.get(col, "") for col in header])
        elif report_type == ReportType.INDIVIDUAL_PERFORMANCE.value:
            writer.writerow(["task_id", "title", "status", "deadline"])
            for task in report.get("tasks", []):
                writer.writerow(
                    [
                        task.get("task_id", ""),
                        task.get("title", ""),
                        task.get("status", ""),
                        task.get("deadline", ""),
                    ]
                )
        elif report_type == ReportType.PROJECT_PROGRESS.value:
            writer.writerow(["metric", "value"])
            writer.writerow(["project_id", report.get("project_id", "")])
            writer.writerow(["total_tasks", report.get("total_tasks", 0)])
            writer.writerow(["completion_rate", report.get("completion_rate", 0.0)])
            writer.writerow(["overdue_tasks", report.get("overdue_tasks", 0)])
            for status_value, count in report.get("status_counts", {}).items():
                writer.writerow(["status:" + str(status_value), count])
        else:
            # Generic fallback: flatten scalar key/value pairs.
            writer.writerow(["key", "value"])
            for key, value in report.items():
                if not isinstance(value, (dict, list)):
                    writer.writerow([key, value])

        return buffer.getvalue()

    def _to_pdf(self, report: Dict[str, object]) -> bytes:
        return _build_pdf(_report_to_lines(report))


# ---------------------------------------------------------------------------
# PDF construction (minimal, standard-library only)
# ---------------------------------------------------------------------------
def _report_to_lines(report: Dict[str, object]) -> List[str]:
    lines = ["Report: {0}".format(report.get("report_type", "report"))]
    for key, value in report.items():
        if key == "report_type":
            continue
        if isinstance(value, dict):
            lines.append("{0}:".format(key))
            for sub_key, sub_value in value.items():
                lines.append("  {0}: {1}".format(sub_key, sub_value))
        elif isinstance(value, list):
            lines.append("{0}: {1} item(s)".format(key, len(value)))
            for item in value:
                lines.append("  - {0}".format(item))
        else:
            lines.append("{0}: {1}".format(key, value))
    return lines


def _pdf_escape(text: str) -> str:
    return (
        text.replace("\\", "\\\\").replace("(", "\\(").replace(")", "\\)")
    )


def _build_pdf(lines: List[str]) -> bytes:
    """Build a minimal, valid single-page PDF rendering ``lines`` as text."""

    content_parts = ["BT", "/F1 12 Tf", "1 0 0 1 50 760 Tm", "14 TL"]
    for index, line in enumerate(lines or [""]):
        if index:
            content_parts.append("T*")
        content_parts.append("({0}) Tj".format(_pdf_escape(line)))
    content_parts.append("ET")
    stream = "\n".join(content_parts).encode("latin-1", "replace")

    objects = [
        b"<< /Type /Catalog /Pages 2 0 R >>",
        b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
        b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
        b"/Resources << /Font << /F1 5 0 R >> >> /Contents 4 0 R >>",
        b"<< /Length "
        + str(len(stream)).encode("ascii")
        + b" >>\nstream\n"
        + stream
        + b"\nendstream",
        b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
    ]

    out = bytearray(b"%PDF-1.4\n")
    offsets = []
    for number, body in enumerate(objects, start=1):
        offsets.append(len(out))
        out += "{0} 0 obj\n".format(number).encode("ascii")
        out += body
        out += b"\nendobj\n"

    xref_position = len(out)
    total = len(objects) + 1
    out += "xref\n0 {0}\n".format(total).encode("ascii")
    out += b"0000000000 65535 f \n"
    for offset in offsets:
        out += "{0:010d} 00000 n \n".format(offset).encode("ascii")
    out += b"trailer\n"
    out += "<< /Size {0} /Root 1 0 R >>\n".format(total).encode("ascii")
    out += b"startxref\n"
    out += "{0}\n".format(xref_position).encode("ascii")
    out += b"%%EOF"
    return bytes(out)


